#include <stdio.h>
int main() {
    int L, B;
    scanf("%d %d", &L, &B);
    int area = L * B;
    int peri = 2 * (L + B);
    if (area > peri) {
        printf("Area\n%d\n", area);
    } else if (peri > area) {
        printf("Peri\n%d\n", peri);
    } else {
        printf("Eq\n%d\n", area);
    }
    return 0;
}

